	/**
	 * The node object model.
	 * @typedef {object} node
	 * @memberof module:PlanningCharts.Model
	 * @prop {string} id The node id.
	 * @prop {color} [color='grey'] The node color.
	 * @prop {color} [unHighlightedColor='grey'] Color for the node when highlighting is on and the node is not highlihgted.
	 * @prop {object} [colors] A dictionary of colors. Example: { "colorMode1" : "red", "colorMode2" : "blue" }. See activeColor in {@link chart.node}.
	 * @prop {Date} start The node start date.
	 * @prop {Date} end The node end date.
	 * @prop {number} [setupEndMs] The setup time for the node, in milliseconds.
	 *	(The setup time displays as a hatched block right before the node. It is the same color as the node, but half its height.)
	 * @prop {number} [transitBeforeMs] The transit time before the node, in milliseconds. (The transit time displays as a block of blue stripes right before the node.)
	 * @prop {number} [transitAfterMs] The transit time after the node, in milliseconds. (The transit time displays as a block of blue stripes right after the node.)
	 * @prop {string} [alertLevel] Displays a horizontal bar at the top of the node.
	 * @prop {string} [bottomAlertLevel] Displays a horizontal bar at the bottom of the node.
	 *	When set to 1, the bar will be colored as set in {@link nodeOptions.load.underColor}. When set to 2, it will be as in {@link nodeOptions.load.overColor}.
	 * @prop {boolean} [followUp=false] Displays a horizontal bar of yellow and black stripes at the bottom of the node.
	 * @prop {boolean|color} [dateFixings=false]  Set to true to display a triangle at the top left of the node with the default fixing color. Set it to a color to draw the triangle with this color.
	 * @prop {string} dteId The associated datatable entry id.
	 * @prop {string|object} [tooltip] The node tooltip content. It can be a string, an HTML-formatted string or an object. The object must have a 'title' property and a 'data' property.
	 *	The 'data' property will contain an array of label/value objects : { label : 'label', value : 'value' }.
	 * @prop {string[]} lines The node inner text. Each array item is displayed on its own line.
	 * @prop {module:PlanningCharts.Model.link[]} [successors] Array of successors this node is linked to.
 * @prop {object[]} [markers] Array of images displayed on the left of the node.
 * Set either the marker.image property to display an image, or marker.font and marker.fontIcon together to display a font icon..
	 * @prop {string} markers.image The image URL, relative to the imagesBaseUrl. See {@link chartOptions.imagesBaseUrl}.
	 * @prop {string} markers.font The web font.
	 * @prop {string} markers.fontIcon The web font icon code.
	 * @prop {number} [markers.fontSize] The web font icon size in pixels.
	 * @prop {"top"|"middle"} [markers.position="top"] The web font icon position.
 * @prop {object[]} [rightMarkers] Array of images displayed on the right of the node.
 * Set either the rightMarker.image property to display an image, or rightMarker.font and rightMarker.fontIcon together to display a font icon..
 * @prop {string} rightMarkers.image The image URL, relative to the imagesBaseUrl. See {@link chartOptions.imagesBaseUrl}.
 * @prop {string} rightMarkers.font The web font.
 * @prop {string} rightMarkers.fontIcon The web font icon code.
 * @prop {number} [rightMarkers.fontSize] The web font icon size in pixels.
 * @prop {"top"|"middle"} [rightMarkers.position="top"] The web font icon position.
	 * @prop {module:PlanningCharts.Enum.pinnedStatus} pinnedStatus Displays a small symbol at the top center of the node.
	 * @prop {boolean} pinOnError Displays an warning icons in the small symbol
	 * @prop {color} pinColor When the pinned status is set to 5 or 6, you can use this property to set the background color of the pin.
	 * @prop {boolean} [completed=false] Draws a hatched pattern on the node.
	 * @prop {number} [completion] Draws a hatched pattern on a percentage of the node width. *completion* is ignored if *completed* is set to true.
 * @prop {number} [verticalCompletion] Draws a vertical hatched pattern on a percentage of the node width.
 * *verticalCompletion* is ignored if *completed* is set to true or if *completion* is set to a valid value.
	 * @prop {color} [completionColor] Color to use as an alternative to the hatched pattern when either *completed* or *completion* is set to true.
	 * @prop {number} [bevelled] Duration, in milliseconds, for which to display a bevelled shape in the node.
	 * @prop {string} [partOf] Set the partOf property of multiple nodes to the same value to indicate that they should be considered as a single object.
	 * @prop {boolean} [draggable=true] Set to false to make this node non-draggable.
	 * @prop {boolean} [extendable=true] Set to false to make this node non-extendable.
	 */
