			x1 = x + checkboxDelta, x2 = x + height - checkboxDelta, y1 = y - halfHeight + checkboxDelta, y2 = y + halfHeight - checkboxDelta;
	
			context.strokeStyle = color;
			context.fillStyle = fillColor;
			context.lineWidth = 1;
			context.beginPath();
		context.moveTo(x1, y1 + checkboxRadius);
		context.lineTo(x1, y2 - checkboxRadius);
		context.quadraticCurveTo(x1, y2, x1 + checkboxRadius, y2);
		context.lineTo(x2 - checkboxRadius, y2);
		context.quadraticCurveTo(x2, y2, x2, y2 - checkboxRadius);
		context.lineTo(x2, y1 + checkboxRadius);
		context.quadraticCurveTo(x2, y1, x2 - checkboxRadius, y1);
		context.lineTo(x1 + checkboxRadius, y1);
		context.quadraticCurveTo(x1, y1, x1, y1 + checkboxRadius);
			context.closePath();
			context.stroke();
			context.fill();
			context.strokeStyle = checkColor;
			context.lineWidth = checkLineWidth;
