				y2 = y + 5,
				x1 = x + 6,
				x2 = x + 12;
	
			context.beginPath();
			context.moveTo(x1, y1);
			context.lineTo(x1, y2);
			context.closePath();
			context.stroke();
	
			context.beginPath();
			context.moveTo(x, y1);
			context.lineTo(x2, y2);
			context.lineTo(x2, y1);
			context.lineTo(x, y2);
