	WebGantt.Util.timezoneRef = {};
	WebGantt.Util.timezoneRevRef = {};
	
	WebGantt.Util.startAtZeroDate = new Date('1973-01-01T00:00:00.000Z').valueOf();
	
	WebGantt.Util.referenceTimezone = function (timezone) {
		WebGantt.Util.timezoneRef[timezone] = {};
		WebGantt.Util.timezoneRevRef[timezone] = {};
	};
	
	WebGantt.Util.adjustTimezoneRevert = function (date, timezone) {
		const dateVal = date.valueOf();
		if (!timezone) { return dateVal; }
		if (!WebGantt.Util.timezoneRevRef[timezone][dateVal]) {
			const d = date instanceof Date ? date : new Date(date),
				dateMs = dateVal;
			if (timezone === 'zero') {
				const toTimezone = new Date(d.toLocaleString('en-US', { timeZone: 'UTC' })),
					diff =  dateMs - toTimezone.getTime();
				WebGantt.Util.timezoneRevRef[timezone][dateVal] = dateMs - diff - WebGantt.Util.startAtZeroDate;
			} else {
				const toTimezone = new Date(d.toLocaleString('en-US', { timeZone: timezone })),
					diff =  dateMs - toTimezone.getTime();
				WebGantt.Util.timezoneRevRef[timezone][dateVal] = dateMs - diff;
			}
		}
		return WebGantt.Util.timezoneRevRef[timezone][dateVal];
	};
	
	WebGantt.Util.adjustTimezone = function (date, timezone) {
		const dateVal = date.valueOf();
		if (!timezone) { return dateVal; }
		if (!WebGantt.Util.timezoneRef[timezone][dateVal]) {
			const d = date instanceof Date ? date : new Date(date),
					dateMs = dateVal;
			if (timezone === 'zero') {
				const toTimezone = new Date(d.toLocaleString('en-US', { timeZone: 'UTC' })),
					diff =  dateMs - toTimezone.getTime();
				WebGantt.Util.timezoneRef[timezone][dateVal] = dateMs + diff + WebGantt.Util.startAtZeroDate;
			} else {
				const toTimezone = new Date(d.toLocaleString('en-US', { timeZone: timezone })),
					diff =  dateMs - toTimezone.getTime();
				WebGantt.Util.timezoneRef[timezone][dateVal] = dateMs + diff;
			}
		}
		return WebGantt.Util.timezoneRef[timezone][dateVal];
	};
	
	WebGantt.Util.getMonday = function (date) {
		const d = new Date(date), day = d.getDay() || 7;
		return day !== 1 ?
			d.setHours(-24 * (day - 1)) :
			d.valueOf();
	};
	
	WebGantt.Util.sortByStart = (a, b) => (a.start - b.start);
	WebGantt.Util.sortNodeRule = (a, b) => (a.start === b.start) ? (b.end - a.end) : (a.start - b.start);
	
