				currentHandlerStyle = style;
				if (style === 'hover') {
					view.shapes.collapseHandler.hover = true;
					view.shapes.collapseHandler.active = false;
				} else if (style === 'active') {
					view.shapes.collapseHandler.hover = true;
					view.shapes.collapseHandler.active = true;
				} else {
					view.shapes.collapseHandler.hover = false;
					view.shapes.collapseHandler.active = false;
				}
