					colIndex = chart.options.datatable.columns.indexOf(srcCol),
				targetCol = (mouse.x >= view.position.width -10) ? undefined : getHeaderColAt(mouse.x);
				let	targetIndex = targetCol ?
						chart.options.datatable.columns.indexOf(view.columnHeaders[targetCol.index]) :
						chart.options.datatable.columns.length;
	
