				WebGantt.Util.Icons.leftChevron(context, params.icons[0].x, params.icons[0].y, chartOptions.searchBar.iconColor, params.icons[0].disabled);
				WebGantt.Util.Icons.rightChevron(context, params.icons[1].x, params.icons[1].y, chartOptions.searchBar.iconColor, params.icons[1].disabled);
