				context.lineTo(path[1].x, path[1].y + radius);
				context.quadraticCurveTo(path[1].x, path[1].y, path[1].x + radius, path[1].y);
				context.lineTo(path[2].x-radius, path[2].y);
				context.quadraticCurveTo(path[2].x, path[2].y, path[2].x, path[2].y + radius);
