				context.lineTo(calendarSelection.x + halfHandle, chartOptions.headHeight);
				context.stroke();
	
				context.strokeStyle = calendarSelection.isOnHandleRight ? chartOptions.selection.calendar.handlesColorHover : chartOptions.selection.calendar.handlesColor;
				context.beginPath();
				context.moveTo(x2 - halfHandle, 0);
				context.lineTo(x2 - halfHandle, chartOptions.headHeight);
