					context.moveTo(x - halfBorderWidth, y1);
					context.lineTo(x - halfBorderWidth, y2);
					context.strokeStyle = borderStyle.color;
					context.lineWidth = borderStyle.width;
					context.closePath();
					context.stroke();
	
